func TestScore_UnmeasuredComplexity_NotScored(t *testing.T) {
	// A TierGeneric unit with zero complexity should never be scored as excellent (maintainability ≠ 0.95).
	// This is a regression test ensuring we don't fabricate an "excellent" score for unmeasured code.
	// For TierGeneric languages, Score() returns nil, meaning no dimensions are computed.
	// The absence of dimensions implies no fabricated excellent score.
	ev := []domain.Evidence{{
		Kind:    domain.EvidenceKindMetrics,
		Source:  "metrics",
		Passed:  true,
		Metrics: map[string]float64{"complexity": 0},
	}}

	// Test with Swift (TierGeneric language)
	scores := engine.Score(ev, policy.EvaluationResult{Passed: true}, "swift")
	if scores != nil {
		t.Errorf("TierGeneric language should return nil scores, got %v", scores)
	}
	// Since scores is nil, maintainability cannot be 0.95 (the old "excellent" default)
	// The nil return indicates no dimensions were computed, preventing fabricated scores.

	// Also test with Python (another TierGeneric language)
	scoresPy := engine.Score(ev, policy.EvaluationResult{Passed: true}, "python")
	if scoresPy != nil {
		t.Errorf("TierGeneric language (python) should return nil scores, got %v", scoresPy)
	}
	if _, ok := scoresPy[domain.DimMaintainability]; ok {
		t.Error("TierGeneric with complexity=0 should not have maintainability dimension set to any value, especially not 0.95")
	}
}

