				"defer_in_loop":     1,
			},
		},
	}
	badScores := engine.Score(badEv, policy.EvaluationResult{Passed: true}, "go")
	if v, ok := badScores[domain.DimArchitecturalFitness]; !ok || v >= 0.80 {
