func TestScore_DefaultsNotInjected(t *testing.T) {
	// Test that TierGeneric units have no default 0.5 dimension values injected.
	// This is a regression test for the fix ensuring that generic/unmeasured
	// languages don't get fabricated dimension scores.
	//
	// TierGeneric languages (swift, python, or empty string) should return nil
	// dimensions and be marked as unsupported (Grade F). The key assertion is
	// that no 0.5 values leak through - either Dimensions is nil (preferred)
	// or no dimension has the hardcoded default value of 0.5.

	// Test with swift language
	swiftUnit := domain.NewUnit(domain.NewUnitID("swift", "main.swift", "CalculateSum"), domain.UnitTypeFunction)
	cfg := domain.ExpiryConfig{
		DefaultWindowDays: 90,
		MinWindowDays:     7,
		MaxWindowDays:     365,
	}
	swiftRecord := engine.CertifyUnit(swiftUnit, nil, []domain.Evidence{}, cfg, time.Now())

	// Assert Unsupported is true for TierGeneric
	if !swiftRecord.Unsupported {
		t.Error("swift (TierGeneric) should have Unsupported=true")
	}

	// Assert Grade is F for unsupported
	if swiftRecord.Grade != domain.GradeF {
		t.Errorf("swift Grade = %v, want F", swiftRecord.Grade)
	}

	// Assert Dimensions is nil - proving no defaults leak through
	// This is the expected guard against default injection
	if swiftRecord.Dimensions != nil {
		// If Dimensions is not nil, verify no 0.5 values were injected
		for dim, val := range swiftRecord.Dimensions {
			if val == 0.5 {
				t.Errorf("dimension %s has hardcoded default 0.5 - defaults are leaking through", dim)
			}
		}
	}

	// Test with python language
	pyUnit := domain.NewUnit(domain.NewUnitID("python", "main.py", "calculate"), domain.UnitTypeFunction)
	pyRecord := engine.CertifyUnit(pyUnit, nil, []domain.Evidence{}, cfg, time.Now())

	if !pyRecord.Unsupported {
		t.Error("python (TierGeneric) should have Unsupported=true")
	}
	if pyRecord.Grade != domain.GradeF {
		t.Errorf("python Grade = %v, want F", pyRecord.Grade)
	}
	if pyRecord.Dimensions != nil {
		for dim, val := range pyRecord.Dimensions {
			if val == 0.5 {
				t.Errorf("dimension %s has hardcoded default 0.5 - defaults are leaking through", dim)
			}
		}
	}

	// Test with empty string language
	emptyUnit := domain.NewUnit(domain.NewUnitID("", "unknown.xyz", "func"), domain.UnitTypeFunction)
	emptyRecord := engine.CertifyUnit(emptyUnit, nil, []domain.Evidence{}, cfg, time.Now())

	if !emptyRecord.Unsupported {
		t.Error("empty language (TierGeneric) should have Unsupported=true")
	}
	if emptyRecord.Grade != domain.GradeF {
		t.Errorf("empty language Grade = %v, want F", emptyRecord.Grade)
	}
	if emptyRecord.Dimensions != nil {
		for dim, val := range emptyRecord.Dimensions {
			if val == 0.5 {
				t.Errorf("dimension %s has hardcoded default 0.5 - defaults are leaking through", dim)
			}
		}
	}
}

func TestScore_SupportedLanguage_StillWorks(t *testing.T) {
	// Construct a Go Unit with realistic CodeMetrics evidence and passing policy
	unit := domain.NewUnit(domain.NewUnitID("go", "main.go", "CalculateSum"), domain.UnitTypeFunction)
	ev := []domain.Evidence{
		evidence.CodeMetrics{
			TotalLines:   150,
			CodeLines:    120,
			CommentLines: 20,
			BlankLines:   10,
			Complexity:   5,
			TodoCount:    0,
		}.ToEvidence(),
		evidence.TestResult{
			Tool:        "go test",
			TotalCount:  20,
			PassedCount: 20,
			FailedCount: 0,
			Coverage:    0.85,
		}.ToEvidence(),
		evidence.LintResult{
			Tool:       "golangci-lint",
			ErrorCount: 0,
		}.ToEvidence(),
	}

	cfg := domain.ExpiryConfig{
		DefaultWindowDays: 90,
		MinWindowDays:     7,
		MaxWindowDays:     365,
	}

	record := engine.CertifyUnit(unit, nil, ev, cfg, time.Now())

	// Assert Grade is one of A/B/C/D/F (not N/A, not empty)
	validGrades := []domain.Grade{domain.GradeA, domain.GradeB, domain.GradeC, domain.GradeD, domain.GradeF}
	gradeValid := false
	for _, g := range validGrades {
		if record.Grade == g {
			gradeValid = true
			break
		}
	}
	if !gradeValid {
		t.Errorf("Grade = %v, want one of A/B/C/D/F", record.Grade)
	}

	// Assert Dimensions is non-nil with entries for maintainability, test-quality, etc.
	if record.Dimensions == nil {
		t.Fatal("Dimensions should not be nil")
	}
	if len(record.Dimensions) == 0 {
		t.Error("Dimensions should have entries")
	}

	// Check for expected dimensions
	expectedDims := []domain.Dimension{
		domain.DimMaintainability,
		domain.DimTestability,
		domain.DimCorrectness,
	}
	for _, dim := range expectedDims {
		if _, ok := record.Dimensions[dim]; !ok {
			t.Errorf("Expected dimension %s to be present in record.Dimensions", dim)
		}
	}

	// Assert Unsupported is false
	if record.Unsupported {
		t.Error("Unsupported should be false for a supported language")
	}
}

